window.__QUIZ_DATA__=[{"id":"theory>Biology>2002>PART I>1>a>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Explain the terms:    parasitism","images":[],"marking_scheme":"Parasitism is a feeding relationship between two organism; in which the parasite lives in or on the body of the host, deriving benefits from it and causing harm to the host. in this relationship the host loses wile the parasite gains","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART I>1>a>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Explain the terms:  commensalism","images":[],"marking_scheme":"Commensalism is a relationship or association between two organism of different species in which one(The commensal) benefit and the other neither loses nor gain","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART I>1>b>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Mention:    One fungal parasite of plant and its host","images":[],"marking_scheme":"- ustilago on maize   - puccinia on maize, wheat or barley  - phytophora palmivora on cocoa  - phytophora infestans on tomatoes/potatoes","marks":"2","difficulty":"2"},{"id":"theory>Biology>2002>PART I>1>b>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Mention:   one bacterial parasite of humans.","images":[],"marking_scheme":"- clostridium tetani(tetanus)  - Neisseria(Gonorrhea)  - Vibrio cholerae(chloera)  - Escherichia coli(dysentery)","marks":"1","difficulty":"2"},{"id":"theory>Biology>2002>PART I>1>c>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"List four symptoms of malaria","images":[],"marking_scheme":"- High temperature/ fever   - loss of apetite  - pains at the joint.  - headache   - Dizziness  - vomiting  - Weakness/tiredness","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART I>1>c>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Mention six methods of controlling malaria in west Africa","images":[],"marking_scheme":"-  Sleeping under mosquito net for prevention  - Applying mosquito repellants  - using anti-malarial drugs in case of infection.  - clearing bushes around the house  - spraying stagnent water in the environment with oil  - Proper drainage to prevent stagnant water which is breeding ground for mosquito  - Educating people on how to control malaria","marks":"4","difficulty":"2"},{"id":"theory>Biology>2002>PART I>2>a","subject":"Biology","year":"2002","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"what is a receptor?","images":[],"marking_scheme":"A receptor is a sensory cell which detects or receives stimuli, initiate and transmit an impulse through neuron to the brain/spinal cord /central nervous system.","marks":"4","difficulty":"1"},{"id":"theory>Biology>2002>PART I>2>b","subject":"Biology","year":"2002","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"Describe the general features common to all receptors","images":[],"marking_scheme":"- consist of a group of sensory cells.  - they have a group of sensory cells hair-like projections known as dentites   -Around their basal portion are nerve fibres which lead to spinal, cranial or central nervous system.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART I>2>c>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"Make a labelled diagram 8cm - 10cm long to show the outer and middle ear of human.","images":["data:image/png;base64,","data:image/jpeg;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Biology>2002>PART I>2>c>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"List three ways of caring for the ear","images":[],"marking_scheme":"- Avoid inserting sharp object into ear  - Regular cleaning eith cotton buds  - Avoid places with loud noise that can damage eardrum   - consult your medical doctor if there is any ear discharge or problem  - Avoid introduction of hot liquid or dangerous chemicals into the ear.  - Treat Disease like measles instantly, because improper care of it can cause deafness","marks":"4","difficulty":"1"},{"id":"theory>Biology>2002>PART I>3>a","subject":"Biology","year":"2002","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"List the main constituents of mammalian blood","images":[],"marking_scheme":"- Blood plasma  - Blood cells(Red blood cells and white blood cells)  - Blood platelets/ Thrombocytes.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2002>PART I>3>b","subject":"Biology","year":"2002","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"State two function of each constituent","images":[],"marking_scheme":"1. Plasma   - Transport end product of digestion or digested food especially glucose and amino acids   -Transport waste products  - Transport antibodies.  - Transport heat from actively respiring tissues  - contains proteins that take part in blood clotting  2. Blood cells  *Red blood cells (Erythrocytes)  - Transport oxygen  -Transport small quantities of CO2  - Take part in blood clotting   * white Blood cells (Leucocytes)  - For defence and breakdown of foreign bodies causing disease  - Lymphocytes produces antibodies/ immunity.  Platelet  - Aids blood clotting","marks":"5","difficulty":"2"},{"id":"theory>Biology>2002>PART I>3>c","subject":"Biology","year":"2002","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Tabulate six differences betwen arteries and veins","images":[],"marking_scheme":"Arteries Veins1. Carry blood away from the heart Carry blood to the heart2. Blood flows under high pressure and it is rapid Blood flows gently under pressure 3. They are thick walled They are thin walled.4. Have elastic walls Walls are inelastic 5. Valves are absentvalves are present 6. Possess narrow lumen  Posses wide lumen 7. Arterials blood is bright red Venous blood is dark red8. It is found deep in the body It is located superfically in the body","marks":"5","difficulty":"2"},{"id":"theory>Biology>2002>PART I>3>d>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Name the main artery which transport blood to the    Lung","images":[],"marking_scheme":"Lung - pulmonary artery","marks":"1","difficulty":"2"},{"id":"theory>Biology>2002>PART I>3>d>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Name the main artery which transport blood to the  Kidney","images":[],"marking_scheme":"Kidney - Renal artery","marks":"1","difficulty":"2"},{"id":"theory>Biology>2002>PART I>4>a","subject":"Biology","year":"2002","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"What is a sexual reproduction?","images":[],"marking_scheme":"Sexual reproduction: is a type of reproduction in which two parent give rise to an offspring that has the unique combination of genes inherited from gametes of the two parents. It involves te fusion of male and female gametes/nuclei from different individual to form zygote which later develops into the embryo.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART I>4>b","subject":"Biology","year":"2002","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State five function of the placenta and four function of the umbilica cord of a mammal","images":[],"marking_scheme":"Function of the placenta  - Attaches fetus to the uterine wall of the mother.  - Filter out urea/nitrogeous waste of baby's blood and transfer to the matter's blood/kidneys.  - Absorbs digested food from mother's blood and pass it to fetus by diffusions.  - Allows passage of antibodies that protect developing fetus from infection  - Prevents mixing of fetal and maternal blood  - Produce hormone that prevent ovulation and menstruation during pregnancy.  Funtion of umbilica cord   - it attaches the fetus to the placenta   - It suspends fetus in amniotic cavity  - The vein in the cord transport digested food from placenta to fetus (Vein also carries oxygenated blood)  - The artery transport waste matabolic products from fetus to placenta  - The vein in the cord carries oxygenated blood while the artery carries deoxygenated.","marks":"4","difficulty":"3"},{"id":"theory>Biology>2002>PART I>4>c","subject":"Biology","year":"2002","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"List four types of placentation in flowering plants","images":[],"marking_scheme":"- Axile (tomato, orange)  - Marginal (legumes)  - Parietal (cucumber or mustard)  - Free-central (primrose, pawpaw)  - Basal (sunflower or marigold)","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART I>4>d","subject":"Biology","year":"2002","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"State four condition necessary for seed germination","images":[],"marking_scheme":"- Viability of seeds  - Moisture/water  - Suitable/optimal temperature  - Adequate suppy of air/ oxygen  - Suitable soil pH","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART II>7>a","subject":"Biology","year":"2002","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"Define ecological succession","images":[],"marking_scheme":"Ecological succession: The orderly series of changes occuring in plant, animals or microbial communites over a period of time resulting in establishment of a climax community","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART II>7>b","subject":"Biology","year":"2002","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"List four charateristics of ecological succession of plants","images":[],"marking_scheme":"- It take place in a barren area or open land newly formed.  - Pioneer or earliest colonizers are hardly grasses and weeds with short life cycle  - The rate of successional chage is initiall rapid but shows down gradually   - It reaches climax or there is attainment of climax communities over a period of time.  - Death of pioneer communities add some organic matter to soil environment, and favours establishment.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART II>7>c","subject":"Biology","year":"2002","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"Explain four factor which affect population size","images":[],"marking_scheme":"- Availability of resources: increase can lea to increase/growth in population and reduction will have adverse effect.  - Migration: will affect population size, when peole leave population reduce while it increases when they come into community.  - disease/disease causing organism.  - Predators: cause reduction in population size.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2002>PART II>7>d","subject":"Biology","year":"2002","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.","question":"State the adaption of tapeworm ( Taenia solium ) to its habitat in gut of human","images":[],"marking_scheme":"- posses hooks on the scolex for attachment to gut wall.  - Has suckers also for attachment to gut wall  - Ribbon-like/Flattened body to fit into gt of host.  - Fast rate of proliferation of proglottides to ensure perpetuation of species.  - Large surface area of the body allows aborption of food from the gut  - Body wall is resistant to digestion by digestive enzymes released by the host  - It is hermaphroditic and this ensures successful sexual reproduction.","marks":"4","difficulty":"3"},{"id":"theory>Biology>2002>PART II>8>a>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Explain the following    producers","images":[],"marking_scheme":"Producer : is a green plants or an autrophs which traps the energy of sunlight and converts it to chemical energy in a process called potosynthesis, CO2 an water is required in this process, and this is the starting point in every food chain.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART II>8>a>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Explain the following   consumer","images":[],"marking_scheme":"Consumer: an organism which derives it nutrients or energy from plants and other organism either directly or indirectly.  - All consumers lack chlorophyll and can be called heterotrophs.  - Consumer that feed on plants directly are herbivores, while those that feed on herbivores are carnivores(or secondary consumers).","marks":"2","difficulty":"1"},{"id":"theory>Biology>2002>PART II>8>a>iii","subject":"Biology","year":"2002","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Explain the following   community","images":[],"marking_scheme":"Community: a group of plants and animals that are found in agiven area an are adapted to the conditions of their environment  - A communities can continue to live successfully and reproduce new offspring and reproduce new offspring.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2002>PART II>8>a>iv","subject":"Biology","year":"2002","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Explain the following   Decomposer","images":[],"marking_scheme":"Decomposer: is a fungus or bacterium or an organism which lives or feed on dead remains of plants and animals, leading to recycling of nutrient. In decomposition organic matter is broken down to produce soluble nutrients which can be absorbed by plants","marks":"2","difficulty":"2"},{"id":"theory>Biology>2002>PART II>8>b>i","subject":"Biology","year":"2002","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"List four charateristics each of    Trees of the trophical rain forest","images":[],"marking_scheme":"-  Trees are predominately woody   - They are stratified   - They have straight columnar trunks with ranches only at the crown.  - They buttresses  - Some are called ''Emergents'' (and attain height of over 60 meters)  - Form canopies at the crown and cast dense shade on the underneath","marks":"3","difficulty":"3"},{"id":"theory>Biology>2002>PART II>8>b>ii","subject":"Biology","year":"2002","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"List four charateristics each of  Tress/shrubs of the savanna","images":[],"marking_scheme":"- Trees/Shrubs are scattered  - Trees are woody, have narrow leaves and few stomata  - Leaves have tick cuticle.  - Most trees are decidous/shed leaves durig dry season  - They have barks which are resistant to fire  - Presence of long tap root with extensive root system","marks":"3","difficulty":"3"}];